    await client.query("DELETE FROM audit_events");

    // Persist workflow_state
    await client.query(
      "INSERT INTO workflow_state (status, next_step, risk_summary) VALUES ($1, $2, $3)",
      [status, nextStep, riskSummary]
    );

    // Persist owner_tasks — one per owner group
    if (isQualified) {
      const dueAt = new Date(nowDate);
      dueAt.setUTCHours(16, 0, 0, 0);
      for (const owner of owners) {
        await client.query(
          "INSERT INTO owner_tasks (owner_group, title, due_at, status) VALUES ($1, $2, $3, $4)",
          [owner, `${owner} recovery review`, dueAt.toISOString(), "open"]
        );
      }
    }

    // Persist customer_messages — customer-safe, no internal ids/codes
    const accountName = doc.name;
    const customerMessage = isQualified
      ? `Dear ${accountName} team, we have identified ${signals.length} active concern${signals.length !== 1 ? "s" : ""} requiring attention on your account. Our recovery team has been engaged and is coordinating across departments to address these matters promptly. You will receive a detailed action plan shortly. We remain committed to your success and resolving these concerns as quickly as possible.`
      : `Dear ${accountName} team, your account is currently in good standing and under standard monitoring. No escalation is required at this time. Our team will continue to proactively monitor your account health and reach out if any concerns arise.`;

    await client.query(
      "INSERT INTO customer_messages (body) VALUES ($1)",
      [customerMessage]
    );

    // Persist audit_events — one customer-visible event
    await client.query(
      "INSERT INTO audit_events (event_type, description, customer_visible) VALUES ($1, $2, $3)",
      [
        "workflow_executed",
        isQualified
          ? `Escalation workflow initiated. ${riskSummary}. Recovery owners notified.`
          : "Account monitoring workflow executed. No escalation required.",
        true,
      ]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

